import React from "react";
import UploadImage from "./UploadImage";

function App() {
  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-8">
      {/* Header Section */}
      <h1 className="text-4xl font-bold text-gray-900 mb-3">Radiology & Oncology AI</h1>
      <p className="text-lg text-gray-600 mb-6 text-center">
        Upload medical images for AI-powered analysis and insights.
      </p>

      {/* Upload Section */}
      <div className="bg-white shadow-lg rounded-lg p-6 w-full max-w-lg">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">Upload Medical Image for Analysis</h2>
        <UploadImage />
      </div>

      {/* AI Report Section */}
      <div className="mt-6 w-full max-w-3xl bg-white shadow-md rounded-lg p-6 border border-gray-200">
        <h2 className="text-2xl font-bold text-gray-800 mb-4">AI Analysis Report</h2>
        <p className="text-gray-700 leading-relaxed text-justify">
          The AI model has analyzed the uploaded image and detected **relevant medical patterns**.  
          Please review the detailed report below for potential findings.  
          Consult a **medical expert** for accurate interpretation.
        </p>
      </div>
    </div>
  );
}

export default App;
